function cargarWhere()
{
     if(Ctrl("oi_evaluacion").GetXValue() != '')
	 {
	     var np, nSQL, i;

		 np = GetProxy();
		 nSQL = np.SQLService(); 	
		 var qry = Ctrl("main").getResource("qry_escala");

		 var result = nSQL.GetXML(qry,"<DATA oi_evaluacion='"+Ctrl("oi_evaluacion").GetXValue()+"' />");

		 var oi_valor = Ctrl("oi_valor").GetXValue(); 
	     Ctrl('oi_valor').SetWhere("OI_FIND = '"+result.GetAttr("oi_escala")+"'"); 
	 	 //Ctrl('oi_valor').SetXValue(oi_valor); 
	 	 if(oi_valor !='') 
	 	 	Ctrl('oi_valor').SetXValue(oi_valor);
	 }

}

function OnChange()
{
   cargarWhere();
}
